import{_ as t,c as o,o as n,O as r}from"./chunks/framework.97fbe135.js";const P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"guide/online.md","lastUpdated":1682417179000}'),s={name:"guide/online.md"},e=r('<ol><li><p>使用Safari浏览器，打开网址：<a href="https://v.sysy.su" target="_blank" rel="noreferrer">https://v.sysy.su</a>。</p></li><li><p>点击iOS星露谷物语修改版/美化版，点击<strong>Online</strong>，点击<strong>在线安装</strong>，在弹出的信息框里点击<strong>安装</strong>，稍等片刻即可在桌面看到安装好的星露谷物语。</p></li><li><p>此时可能会出现两种情况：</p><ol><li><p>提示“无法安装‘Stardew Valley’，无法安装此App，因为无法验证其完整性”，这表示掉签了，需要等待我更新证书。</p></li><li><p>提示“未受信任的企业级开发者”，这时需要打开手机的<strong>设置-通用-VPN与设备管理</strong>，在<strong>企业级App</strong>下方找到证书，点进去信任一下，返回桌面重新打开游戏，这时候你应该可以正常打开游戏了。</p></li></ol></li><li><p>如果玩了一段时间突然发现游戏打不开了，提示“无法验证App”或者打开闪退，这也表示掉签了，需要我更新证书后重新安装，重新安装必须先卸载游戏，不然无法更新证书，所以卸载游戏前请先备份存档。</p></li><li><p>关于如何备份存档，请打开手机的<strong>文件</strong>App，点击<strong>我的iPhone/iPad-Stardew Valley</strong>，此时应该能看到一个以你星露谷角色名命名的文件夹，<strong>长按</strong>这个文件夹，点击<strong>拷贝1项</strong>，然后返回到<strong>我的iPhone/iPad</strong>这个目录，长按空白处，点击<strong>粘贴</strong>，这时候就备份好你的存档了。</p></li><li><p>关于如何恢复存档，请打开手机的<strong>文件</strong>App，点击<strong>我的iPhone/iPad</strong>，找到你之前备份的以你星露谷角色名命名的存档文件夹，<strong>长按</strong>这个文件夹，点击<strong>移动</strong>，返回<strong>我的iPhone/iPad</strong>目录，找到<strong>Stardew Valley</strong>文件夹，点进去之后点击<strong>右上角的移动</strong>，此时会提示“替换现有项目”，选择<strong>替换</strong>，这时候就恢复你的存档了。</p></li></ol>',1),i=[e];function g(l,a,p,_,d,c){return n(),o("div",null,i)}const f=t(s,[["render",g]]);export{P as __pageData,f as default};
